SELECT SUM(copies_available) AS total_copies
FROM resources
WHERE author = 'John Doe';

SELECT COUNT(lending_id) AS total_lent_out
FROM lendings
WHERE status = 'lent';

SELECT shelf_name
FROM shelves
WHERE current_occupancy > 40;

SELECT COUNT(*) AS total_resources, category
FROM resources
GROUP BY category;

SELECT COUNT(lending_id) AS total_lent_books
FROM lendings
WHERE status = 'lent';

SELECT student_id, student_name, email, enrollment_date
FROM students
ORDER BY enrollment_date DESC;

SELECT COUNT(*) AS total_books_lent
FROM lendings
WHERE status = 'lent';

SELECT 
  (SELECT COUNT(*) FROM students WHERE status = 'active') AS active_students,
  (SELECT COUNT(*) FROM professors WHERE status = 'active') AS active_professors;
